    auto has_column = [&](const std::string& table, const std::string& column) {
      const auto res = sqlgen::exec(conn, "SELECT 1 WHERE EXISTS("
        "SELECT 1 FROM pragma_table_info('" + table + "') WHERE name='" + column + "');");
      return res.has_value();
    };

