      course_id INTEGER PRIMARY KEY,
      title VARCHAR(100) NOT NULL
    )
  )").value();

  conn->execute(R"(
    CREATE TABLE IF NOT EXISTS Enrollment (
      enrollment_id INTEGER PRIMARY KEY,
      course_id INTEGER REFERENCES Course(course_id),
      grade REAL
    )
  )").value();

  // 3. Build and execute the query
  auto query = sqlgen::select_from<Course>("title"_c, 
                                          sqlgen::count("enrollment_id"_c).as("student_count"),
                                          sqlgen::avg("grade"_c).as("avg_grade"))
             | sqlgen::left_join<Enrollment>("course_id"_c == "course_id"_c)
