Based on the reference materials and detailed specifications, here's the complete implementation for the `migration_add_column` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_migration_add_column {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct UserAfter {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;
  std::string username;
  std::string phone_number;
  bool is_active;
};

/**
 * Function: Perform schema migration to add new columns.
 * 
 * @return true if migration succeeds, false otherwise
 */
bool migration_add_column() {
  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = *conn_result;

  // 2. Get CREATE TABLE statements for both structs
  auto user_create_stmt = sqlgen::transpilation::to_create_table<User>();
  auto user_after_create_stmt = sqlgen::transpilation::to_create_table<UserAfter>();

  // 3. Extract the ALTER TABLE statements from the differences
  std::vector<std::string> alter_statements;

  // Compare columns to find differences
  auto user_columns = user_create_stmt.columns;
  auto user_after_columns = user_after_create_stmt.columns;

  // Create sets for easier comparison
  std::set<std::string> user_col_names;
  for (const auto& col : user_columns) {
    user_col_names.insert(col.name);
  }

  // Find columns that exist in UserAfter but not in User
  for (const auto& col : user_after_columns) {
    if (user_col_names.find(col.name) == user_col_names.end()) {
      // Convert column to SQL and create ALTER TABLE statement
      std::string column_sql = sqlgen::sqlite::to_sql(col);
      alter_statements.push_back("ALTER TABLE User ADD COLUMN " + column_sql);
    }
  }

  // 4. Execute the ALTER TABLE statements
  for (const auto& stmt : alter_statements) {
    auto exec_result = conn->execute(stmt);
    if (!exec_result) {
      return false; // Execution failed
    }
  }

  return true; // Migration succeeded
}

} // namespace schema_migration_add_column
```

