std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  // Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create temporary table and insert events
  auto create_table_sql = R"(
    CREATE TEMPORARY TABLE IF NOT EXISTS temp_event (
      event_id INTEGER PRIMARY KEY,
      event_name TEXT NOT NULL,
      start_time DATETIME NOT NULL,
      end_time DATETIME,
      created_at DATETIME NOT NULL
    )
  )";

  auto insert_sql = "INSERT INTO temp_event (event_id, event_name, start_time, end_time, created_at) VALUES ";
  std::string values;
  for (size_t i = 0; i < events.size(); ++i) {
    if (i > 0) values += ", ";
    values += "(" + std::to_string(events[i].event_id) + ", '" + events[i].event_name + "', '" + 
              events[i].start_time.value().format("%Y-%m-%d %H:%M:%S") + "', ";
    if (events[i].end_time) {
      values += "'" + events[i].end_time.value().format("%Y-%m-%d %H:%M:%S") + "'";
    } else {
      values += "NULL";
    }
    values += ", '" + events[i].created_at.value().format("%Y-%m-%d %H:%M:%S") + "')";
  }

  auto execute_result = conn->execute(create_table_sql + " " + insert_sql + " " + values);
  if (!execute_result) {
