  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  std::string email;
};

struct ValidatedProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string trimmed_name;
  std::string trimmed_email;
  int name_length;
  int email_length;
};

/**
 * description: trim_and_length_validation.
 * This function demonstrates how to trim whitespace from string columns and validate their lengths using sqlgen read API.
 * It returns a vector of ValidatedProfile structs, where each struct contains the user_id, trimmed_name, trimmed_email, name_length, and email_length.
 * Returns: std::vector<ValidatedProfile>.
 */
std::vector<ValidatedProfile> trim_and_length_validation() {
  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {}; // Return empty vector on connection failure
  }
  auto conn = *conn_result;

  // 2. Use sqlgen read API to retrieve all records from UserProfile table
  auto read_result = sqlgen::read<std::vector<UserProfile>>(conn);
  if (!read_result) {
    return {}; // Return empty vector on read failure
  }
  auto profiles = *read_result;

  // 3. Apply SQL functions (ltrim, rtrim, trim, length) to trim and measure string lengths
  std::vector<ValidatedProfile> validated_profiles;
  validated_profiles.reserve(profiles.size());

  for (const auto& profile : profiles) {
    // Trim whitespace from name and email using SQL functions
    std::string trimmed_name = sqlgen::trim(profile.name);
    std::string trimmed_email = sqlgen::trim(profile.email);

    // Compute lengths of the trimmed strings
    int name_length = trimmed_name.length();
    int email_length = trimmed_email.length();

    // Create validated profile object
    ValidatedProfile validated_profile{
        .user_id = profile.user_id,
        .trimmed_name = trimmed_name,
        .trimmed_email = trimmed_email,
        .name_length = name_length,
        .email_length = email_length
    };

    validated_profiles.push_back(validated_profile);
  }

  // 4. Return the processed data as a vector of ValidatedProfile objects
  return validated_profiles;
}

}  // namespace trim_and_length_validation

