  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {}; // Return empty vector on connection failure
  }
  auto conn = conn_result.value();

  // 2. Read Sales data from database
  auto sales_result = sqlgen::read<std::vector<Sales>>(conn);
  if (!sales_result) {
    return {}; // Return empty vector on read failure
  }
  auto sales_data = sales_result.value();

  // 3. Process each sale to extract weekday and aggregate totals
  std::vector<WeekdayStats> stats;
  for (const auto& sale : sales_data) {
    // Extract weekday from sale_time using sqlgen's date_part function
    auto weekday = sqlgen::internal::to_weekday(sale.sale_time);

    // Find existing entry for this weekday or create new one
    bool found = false;
    for (auto& stat : stats) {
      if (stat.weekday == weekday) {
        stat.total_quantity += sale.quantity;
        found = true;
        break;
      }
    }
    if (!found) {
      stats.push_back({weekday, sale.quantity});
    }
  }

  // 4. Sort results by weekday
  std::sort(stats.begin(), stats.end(), 
              [](const WeekdayStats& a, const WeekdayStats& b) {
                return a.weekday < b.weekday;
              });

  return stats;
}

}  // namespace weekday_sales_analysis
